DELETE FROM DDD_INQUIRY
WHERE INQUIRY_NUMBER = #{inquiryNumber}
AND USER_NUMBER = #{userNumber}

mapper.select:

SELECT * FROM (
    SELECT ROWNUM rnum, sub.*
    FROM (
        SELECT
            ANSWER_STATUS,
            INQUIRY_NUMBER,
            INQUIRY_TITLE,
            INQUIRY_DATE,
            USER_NUMBER
        FROM DDD_INQUIRY
        WHERE USER_NUMBER = #{userNumber}
        ORDER BY INQUIRY_NUMBER DESC
    ) sub
    WHERE ROWNUM <= #{endRow}
)
WHERE rnum >= #{startRow}

SELECT COUNT(*)
FROM DDD_INQUIRY
WHERE USER_NUMBER = #{userNumber}
